import './Projects.css';
import React, {useState, useEffect} from 'react';

import thumb from './img/thumb.jpg';


function ProjectThumb() {

  return (
    <div className="thumbContainer"> 
        <img src={thumb} className="thumbImg" />
        <p>Project Page #1</p>
    </div>
  );
}

export default ProjectThumb;
